```rust
// crates/kanban-tui/src/ui/debug_screen.rs

pub fn render_debug_screen(app: &App, frame: &mut Frame, area: Rect) {
    let entries = app.log_buffer.recent(100);
    let mut lines = vec![];

    if entries.is_empty() {
        lines.push(Line::from(Span::styled("  No log entries", label_text())));
    } else {
        for entry in entries.iter().rev() {
            let (level_str, level_style) = match entry.level {
                LogLevel::Error => ("ERROR", Style::default().fg(Color::Red).add_modifier(Modifier::BOLD)),
                LogLevel::Warn  => ("WARN ", Style::default().fg(Color::Yellow)),
            };
            let time = entry.timestamp.format("%H:%M:%S");

            // Header line: time + level + target
            lines.push(Line::from(vec![
                Span::styled(format!("{} ", time), label_text()),
                Span::styled(format!("{} ", level_str), level_style),
                Span::styled(format!("[{}]", entry.target), label_text()),
            ]));
            // Message line: indented
            lines.push(Line::from(Span::styled(
                format!("  {}", entry.message),
                normal_text(),
            )));
            // Blank separator
            lines.push(Line::from(""));
        }
    }

    let entry_count = app.log_buffer.len();
    let block = Block::default()
        .borders(Borders::ALL)
        .border_style(focused_border())
        .title("Debug Log (F12 or Esc to close, c to clear)");

    let content = Paragraph::new(lines).block(block);
    frame.render_widget(content, area);

    // Status line at bottom
    // ... render "N entries  F12:close  c:clear  j/k:scroll"
}
```

